from openpyxl import Workbook
from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
from openpyxl.utils import get_column_letter

wb = Workbook()

# Styles (brutalist patriotic inspired)
header_font = Font(name='Arial', size=12, bold=True, color='FFFFFF')
header_fill = PatternFill(start_color='0A1F3D', end_color='0A1F3D', fill_type='solid')
accent_fill = PatternFill(start_color='EC1024', end_color='EC1024', fill_type='solid')
paper_fill = PatternFill(start_color='F4F0E6', end_color='F4F0E6', fill_type='solid')
thin_border = Border(
    left=Side(style='thin', color='1A3358'),
    right=Side(style='thin', color='1A3358'),
    top=Side(style='thin', color='1A3358'),
    bottom=Side(style='thin', color='1A3358')
)

def style_header(ws, row, cols):
    for col in range(1, cols + 1):
        cell = ws.cell(row=row, column=col)
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = Alignment(horizontal='left', vertical='center', wrap_text=True)
        cell.border = thin_border

def add_data(ws, start_row, data, header=False):
    for i, row_data in enumerate(data):
        for j, val in enumerate(row_data):
            cell = ws.cell(row=start_row + i, column=j + 1, value=val)
            cell.border = thin_border
            cell.alignment = Alignment(wrap_text=True, vertical='top')
            if header and i == 0:
                cell.font = Font(bold=True, color='FFFFFF')
                cell.fill = header_fill
            elif i % 2 == 0:
                cell.fill = paper_fill

